from flask import Flask, request, jsonify
import redis
import logging

app = Flask(__name__)

# Configure Redis connection
redis_client = redis.Redis(
    host='localhost',
    port=6379,
    db=0,
    decode_responses=True,
    socket_connect_timeout=5,
    socket_timeout=5
)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Whitelist of allowed Redis commands
ALLOWED_COMMANDS = {
    'GET', 'SET', 'DEL', 'EXISTS', 'TTL', 'PTTL', 'KEYS', 
    'SCAN', 'INFO', 'FLUSHDB', 'FLUSHALL', 'DBSIZE',
    'HGET', 'HSET', 'HDEL', 'HGETALL', 'HKEYS', 'HVALS',
    'LPUSH', 'RPUSH', 'LPOP', 'RPOP', 'LRANGE', 'LLEN',
    'SADD', 'SREM', 'SMEMBERS', 'SISMEMBER', 'SCARD',
    'ZADD', 'ZREM', 'ZRANGE', 'ZCARD', 'ZSCORE'
}

def validate_command(command):
    """Validate that the command is in the allowed list"""
    if not command:
        return False
    return command.upper() in ALLOWED_COMMANDS

def sanitize_input(input_str):
    """Sanitize input to prevent injection attacks"""
    if not isinstance(input_str, str):
        return None
    # Remove potentially dangerous characters
    dangerous_chars = [';', '&', '|', '`', '$', '(', ')', '{', '}']
    for char in dangerous_chars:
        if char in input_str:
            return None
    return input_str.strip()

@app.route('/redis', methods=['GET'])
def execute_redis_command():
    try:
        command = request.args.get('command', '').strip()
        
        if not command:
            return jsonify({'error': 'No command provided'}), 400
            
        # Validate command
        if not validate_command(command):
            return jsonify({'error': 'Command not allowed'}), 400
            
        # Parse command arguments
        args = []
        for key in request.args:
            if key != 'command':
                value = sanitize_input(request.args.get(key))
                if value is None:
                    return jsonify({'error': 'Invalid argument provided'}), 400
                args.append(value)
        
        # Execute command
        result = redis_client.execute_command(command.upper(), *args)
        
        # Log the execution
        logger.info(f"Executed Redis command: {command} with args: {args}")
        
        return jsonify({'result': result})
        
    except redis.exceptions.ConnectionError:
        logger.error("Redis connection error")
        return jsonify({'error': 'Redis connection failed'}), 500
    except redis.exceptions.ResponseError as e:
        logger.error(f"Redis response error: {str(e)}")
        return jsonify({'error': f'Redis error: {str(e)}'}), 400
    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)